parameters.query:
SELECT key, value FROM app_settings WHERE key IN ('ai_model', 'ai_base_url', 'ai_system_prompt')
UNION ALL
SELECT 'recent_titles' AS key, COALESCE(array_to_json(array_agg(title ORDER BY created_at DESC))::text, '[]') AS value FROM (SELECT title, created_at FROM content_ideas ORDER BY created_at DESC LIMIT 50) t;

parameters.jsCode:
const rows = $('⚙️ Настройки из БД').all().map(i => i.json);
const settingsMap = {};
for (const r of (Array.isArray(rows[0]) ? rows[0] : rows)) {
  if (r.key === 'recent_titles') {
    try { settingsMap.recent_titles = JSON.parse(r.value || '[]'); } catch(e) { settingsMap.recent_titles = []; }
  } else if (r.key) {
    settingsMap[r.key] = r.value;
  }
}
// Accept input from webhook, cron schedule, or manual test trigger
const webhookItems = (() => { try { return $('📥 Webhook').all();         } catch(e) { return []; } })();
const cronItems    = (() => { try { return $('Cron параметры').all();     } catch(e) { return []; } })();
const testItems    = (() => { try { return $('🧪 Тестовые данные').all(); } catch(e) { return []; } })();
const sourceItems  = webhookItems.length ? webhookItems : (cronItems.length ? cronItems : testItems);
const raw  = sourceItems.length ? sourceItems[0].json : {};
const body = raw.body || raw;
return [{ json: {
  ai_base_url: settingsMap.ai_base_url || 'https://gptunnel.ru/v1',
  ai_model: settingsMap.ai_model || 'gpt-4o',
  system_prompt: body.system_prompt || settingsMap.ai_system_prompt || 'Ты — креативный маркетолог.',
  count: body.count || 3,
  product_name: body.product_name || '',
  niche: body.niche || '',
  extra_instructions: body.extra_instructions || '',
  content_type: body.content_type || 'a2e_product',
  script_template: body.script_template || 'auto',
  recent_titles: settingsMap.recent_titles || []
}}];

const cfg = $input.first().json;
const contentType = cfg.content_type || 'a2e_product';
const isA2EProduct = contentType === 'a2e_product';
const isHeygen = contentType === 'heygen';
const scriptTemplate = cfg.script_template || 'auto';

const templateHints = {
  'review': 'Сценарный приём: обзор/рецензия — подробный разбор продукта с плюсами и минусами.',
  'unboxing': 'Сценарный приём: распаковка — первое впечатление, эмоции, surprise-момент.',
  'ad': 'Сценарный приём: рекламный ролик — акцент на УТП, эмоции, призыв к покупке.',
  'comparison': 'Сценарный приём: сравнение — продукт vs аналоги или vs ожидания.',
  'tutorial': 'Сценарный приём: обучение/лайфхак — как использовать продукт нестандартно.',
  'auto': ''
};
const templateHint = templateHints[scriptTemplate] || '';

const formatHint = isA2EProduct
  ? '

ФОРМАТ: АНИМИРОВАННОЕ ПРОДУКТОВОЕ ВИДЕО. Фото продукта оживляется с помощью AI (image-to-video). Нет аватара, нет речи — только визуальная анимация продукта. Идеи должны фокусироваться на динамичной подаче продукта: вращение, крупные планы, красивые ракурсы, движение камеры. Подходит для: витрин, карточек товаров, промо-постов.'
  : '

ФОРМАТ: АВАТАР HEYGEN (Talking Head). Ведущий-аватар говорит на камеру с lip-sync озвучкой. Нет взаимодействия с продуктом напрямую. Акцент на: речевой нарратив, подача, вовлечённость. Подходит для: экспертного контента, объяснений, историй, советов.';

const systemPrompt = cfg.system_prompt + formatHint + (templateHint ? '

' + templateHint : '') + '

Ты — опытный контент-стратег и маркетолог, специализирующийся на создании вирусного короткого видеоконтента для маркетплейсов и соцсетей (Wildberries, Ozon, VK Клипы, YouTube Shorts, TikTok, Reels).

Твоя задача — генерировать детальные, продуманные и уникальные идеи для коротких вертикальных видео (15-60 сек).

Требования к каждой идее:
- Цепляющий заголовок, который останавливает скролл (до 60 символов)
- Чёткая концепция с конкретным сценарным приёмом: до/после, распаковка, лайфхак, сравнение, сторителлинг, шоковый-факт, ASMR, таймлапс, юмор
' + (isA2EProduct ? '- Детальное описание анимации: движение камеры, ракурсы, что показать, как оживить фото продукта
' : '- Стиль подачи аватара, настроение и тональность речи, ключевые фразы
') + '- Целевая аудитория с возрастом, полом, интересами
- Тональность, подходящая для аудитории

Каждая идея должна использовать РАЗНЫЙ сценарный приём!
- Используй только достоверные факты. Не выдумывай статистику, исследования или конкретные цифры.
- Каждая идея принципиально отличается по теме и сценарному приёму от остальных в запросе.

Отвечай СТРОГО в JSON:
{
  "ideas": [
    {
      "title": "Цепляющий заголовок (до 60 символов)",
      "category": "обзор | лайфхак | до-после | распаковка | сравнение | сторителлинг | юмор | образование | ASMR",
      "concept": "Подробная концепция видео на 3-5 предложений",
      "visual_description": "' + (isA2EProduct ? 'Детальное визуальное описание: анимация продукта, движение камеры, ракурсы, фон, освещение' : 'Стиль подачи аватара HeyGen, настроение, фон') + '",
      "target_audience": "Пол, возраст 18-35, интересы",
      "tone": "энергичный | спокойный | юмористический | экспертный | вдохновляющий"
    }
  ]
}';
let userMsg = `Сгенерируй ${cfg.count} уникальных идей для вертикальных коротких видео (15-60 сек). Каждая идея должна использовать РАЗНЫЙ сценарный приём.`;
if (cfg.product_name) userMsg += `
Продукт: ${cfg.product_name}.`;
if (cfg.niche) userMsg += `
Ниша: ${cfg.niche}.`;
if (cfg.extra_instructions) userMsg += `
Дополнительно: ${cfg.extra_instructions}`;
if (isA2EProduct) userMsg += '
Формат: анимированное продуктовое видео из фото (image-to-video). Без аватара. Только визуальная анимация продукта.';
else userMsg += '
Формат: talking head аватар HeyGen с lip-sync озвучкой.';
if (cfg.recent_titles && cfg.recent_titles.length > 0) {
  userMsg += '

УЖЕ СОЗДАННЫЕ ИДЕИ (НЕ ПОВТОРЯЙ эти темы — генерируй принципиально иные):
' + cfg.recent_titles.slice(0, 30).map((t, i) => (i+1) + '. ' + t).join('
');
}
userMsg += '
Важно: каждая идея самодостаточная — достаточно деталей для сценария и видеопромпта.';
return [{ json: {
  url: cfg.ai_base_url + '/chat/completions',
  body: JSON.stringify({
    model: cfg.ai_model,
    temperature: 0.80,
    max_tokens: 4000,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMsg }
    ]
  }),
  content_type: contentType
}}];

const response = $input.first().json;
const body = response.body || response;
const contentType = $('🏗️ Тело запроса идей').first().json.content_type || 'regular';
let parsed;
try {
  const content = body.choices[0].message.content;
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('AI ideas parse error: ' + e.message);
}
const ideas = parsed.ideas || [];
if (ideas.length === 0) throw new Error('AI returned empty ideas list');
return ideas.map(idea => ({ json: { ...idea, content_type: contentType } }));

const config = $('🔧 Подготовка конфига').first().json;
return $input.all().map(item => ({
  json: {
    idea_id: item.json.id,
    title: item.json.title,
    concept: item.json.concept,
    visual_description: item.json.visual_description || '',
    target_audience: item.json.target_audience || '',
    tone: item.json.tone || '',
    category: item.json.category || '',
    content_type: item.json.content_type || config.content_type || 'regular',
    ai_base_url: config.ai_base_url,
    ai_model: config.ai_model
  }
}));

return $input.all().map(item => {
  const ctx = item.json;
  const isA2EProduct = ctx.content_type === 'a2e_product';

  const systemPrompt = isA2EProduct
    ? 'Ты — специалист по копирайтингу для коротких продуктовых видео.

Формат: анимированное видео из фото продукта (image-to-video). Аватара нет. Речи нет.

Твоя задача — написать:
- Текст для субтитров / текстовых оверлеев (3-7 коротких фраз)
- Описание визуальной анимации продукта

Отвечай СТРОГО в JSON:
{
  "script_text": "Текст для оверлеев: короткие фразы через |. Пример: Новинка! | Как это работает? | Попробуй сам!",
  "hook": "Первая фраза-хук",
  "cta": "Призыв к действию",
  "word_count": 15,
  "duration_hint": 15,
  "timing_marks": [
    { "time": 0, "text": "Хук" },
    { "time": 5, "text": "Фраза 2" },
    { "time": 10, "text": "CTA" }
  ]
}'
    : 'Ты — профессиональный сценарист коротких видео в формате Talking Head (аватар HeyGen говорит на камеру).

Требования к сценарию:
- Первые 2-3 сек: МОЩНЫЙ хук (вопрос, шокирующий факт, провокация)
- Далее: раскрытие темы с нарастающим интересом
- Кульминация: ключевое раскрытие / вау-момент
- Финал: призыв к действию
- Язык: живой, разговорный
- Длина: 80-150 слов (35-55 сек)
- Только достоверные факты

Отвечай СТРОГО в JSON:
{
  "script_text": "Полный текст речи аватара для озвучки",
  "hook": "Хук — первая фраза",
  "cta": "Призыв к действию",
  "word_count": 95,
  "duration_hint": 40,
  "timing_marks": [
    { "time": 0, "text": "Хук" },
    { "time": 3, "text": "Фраза 1" },
    { "time": 10, "text": "Фраза 2" },
    { "time": 20, "text": "Кульминация" },
    { "time": 30, "text": "CTA" }
  ]
}';

  let userMsg = isA2EProduct
    ? `Напиши текст для субтитров/оверлеев продуктового видео (анимация фото).

Идея: ${ctx.title}
Категория: ${ctx.category}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Аудитория: ${ctx.target_audience}

Важно: аватара нет, речи нет. Только короткие текстовые фразы на экране + описание анимации.`
    : `Напиши текст речи аватара HeyGen для вертикального видео.

Идея: ${ctx.title}
Категория: ${ctx.category}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Аудитория: ${ctx.target_audience}
Визуал: ${ctx.visual_description}

Важно: talking head формат, естественная речь.`;

  return { json: {
    url: ctx.ai_base_url + '/chat/completions',
    body: JSON.stringify({
      model: ctx.ai_model,
      temperature: 0.75,
      max_tokens: 3000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    })
  }};
});

const ctxAll = $('🔗 Контекст для сценария').all();
return $input.all().map((item, idx) => {
  const body = item.json.body || item.json;
  let parsed;
  try {
    const content = body.choices[0].message.content;
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error('Script parse error at index ' + idx + ': ' + e.message);
  }
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  return { json: {
    ...parsed,
    idea_id: myCtx.idea_id,
    title: myCtx.title,
    concept: myCtx.concept,
    visual_description: myCtx.visual_description,
    target_audience: myCtx.target_audience,
    tone: myCtx.tone,
    category: myCtx.category,
    content_type: myCtx.content_type,
    ai_base_url: myCtx.ai_base_url,
    ai_model: myCtx.ai_model
  }};
});

const ctxAll = $('🔗 Контекст для сценария').all();
const scriptAll = $('📋 Парсинг сценария').all();
return $input.all().map((item, idx) => {
  const scriptSaved = item.json;
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  const myScript = (scriptAll[idx] || scriptAll[0]).json;
  return { json: {
    idea_id: myCtx.idea_id,
    script_id: scriptSaved.id,
    title: myCtx.title,
    concept: myCtx.concept,
    visual_description: myCtx.visual_description,
    target_audience: myCtx.target_audience,
    tone: myCtx.tone,
    category: myCtx.category,
    content_type: myCtx.content_type,
    script_text: myScript.script_text || '',
    hook: myScript.hook || '',
    timing_marks: myScript.timing_marks || [],
    ai_base_url: myCtx.ai_base_url,
    ai_model: myCtx.ai_model
  }};
});

return $input.all().map(item => {
  const ctx = item.json;
  const isA2EProduct = ctx.content_type === 'a2e_product';
    const isHeygen = ctx.content_type === 'heygen';

  const systemPrompt = isA2EProduct
    ? 'Ты — специалист по созданию промптов для A2E image-to-video генерации. Твоя задача — создать промпт для анимации фото продукта в динамичное видео.

Требования:
- Промпт на АНГЛИЙСКОМ языке
- Плавное кинематографичное движение камеры
- Стиль: product video, cinematic, smooth motion, photorealistic
- 50-80 слов
- Подчёркивай продукт: крупные планы, свет, детали

Отвечай СТРОГО в JSON:
{
  "prompt_text": "A2E image-to-video prompt in English, 50-80 words describing cinematic product animation",
  "scene_descriptions": [
    {
      "order": 1,
      "duration": 7,
      "description": "Product showcase scene in English",
      "camera_movement": "slow zoom-in | orbital | dolly",
      "transition": "fade"
    }
  ],
  "style_reference": "product-shot",
  "aspect_ratio": "9:16",
  "mood": "Dynamic",
  "color_palette": "Clean background, product colors"
}'
    : 'Ты — помощник, описывающий стиль и настроение видео с аватаром HeyGen.

Для формата HeyGen Talking Head опиши:
- Общее настроение видео
- Рекомендуемый фон
- Стиль субтитров
- Темп подачи

Отвечай СТРОГО в JSON:
{
  "prompt_text": "Brief style and mood description for HeyGen talking head",
  "scene_descriptions": [
    {
      "order": 1,
      "duration": 0,
      "description": "Overall HeyGen avatar video style",
      "camera_movement": "static",
      "transition": "none"
    }
  ],
  "style_reference": "talking-head",
  "aspect_ratio": "9:16",
  "mood": "Dynamic | Calm | Exciting",
  "color_palette": "Background color suggestion"
}';

  const userMsg = isA2EProduct
    ? `Создай промпт для A2E image-to-video анимации фото продукта.

Продukт: ${ctx.title}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Описание: ${ctx.visual_description}

Промпт должен описывать анимацию этого продукта:
- плавные движения камеры
- акцент на деталях
- профессиональный стиль

Важно: prompt_text на АНГЛИЙСКОМ`
    : `Опиши стиль и настроение для видео с аватаром HeyGen.

Идея: ${ctx.title}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Аудитория: ${ctx.target_audience}

Сценарий речи:
${ctx.script_text}

Опиши стиль подачи, настроение, рекомендуемый фон.`;

  return { json: {
    url: ctx.ai_base_url + '/chat/completions',
    body: JSON.stringify({
      model: ctx.ai_model,
      temperature: 0.8,
      max_tokens: 3000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    })
  }};
});

const ctxAll = $('🔗 Контекст для видео-промпта').all();
return $input.all().map((item, idx) => {
  const body = item.json.body || item.json;
  let parsed;
  try {
    const content = body.choices[0].message.content;
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error('Video prompt parse error at index ' + idx + ': ' + e.message);
  }
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  return { json: {
    ...parsed,
    idea_id: myCtx.idea_id,
    script_id: myCtx.script_id
  }};
});

const ideas = $('💾 Сохранить идею').all().map(i => i.json);
const scripts = $('💾 Сохранить сценарий').all().map(i => i.json);
const prompts = $('💾 Сохранить видео-промпт').all().map(i => i.json);
return [{
  json: {
    success: true,
    count: ideas.length,
    ideas: ideas.map((idea, idx) => ({
      idea: idea,
      voice_script: scripts[idx] || null,
      video_prompt: prompts[idx] || null
    }))
  }
}];

// Тестовые данные для запуска без вебхука
return [{ json: { body: {
  content_type: "a2e_product",
  product_name: "Переноска для питомцев",
  niche: "Товары для животных",
  count: 1,
  extra_instructions: "Короткий вертикальный формат, акцент на безопасность",
  script_template: "auto"
} } }];
